import{_ as e,o as a,c as r,ag as s}from"./chunks/framework.BGkQCay2.js";const p=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"guide/benchmarks.md","filePath":"guide/benchmarks.md"}'),n={name:"guide/benchmarks.md"};function i(d,t,o,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[s(`<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><p>Performance comparisons between Vex and other systems programming languages.</p><blockquote><p><strong>IMPORTANT:</strong> All numbers on this page are <strong>illustrative estimates</strong> based on LLVM backend performance characteristics and known algorithmic complexity. Vex is pre-1.0 -- real benchmarks will be published as the compiler matures. Run <code>vex test --bench</code> for current measurements on your hardware.</p></blockquote><h2 id="benchmark-methodology" tabindex="-1">Benchmark Methodology <a class="header-anchor" href="#benchmark-methodology" aria-label="Permalink to &quot;Benchmark Methodology&quot;">​</a></h2><ul><li><strong>Hardware:</strong> Apple M2 Pro, 32 GB RAM (unless noted)</li><li><strong>OS:</strong> macOS 14, Linux 6.5</li><li><strong>Compiler versions:</strong> Vex 0.1.2, Rust 1.80, Go 1.22, Zig 0.12, C (Clang 17)</li><li><strong>Optimization:</strong> <code>-O3</code> (Vex), <code>--release</code> (Rust), <code>-O3</code> (C/Zig), default (Go)</li><li><strong>Measurement:</strong> <code>vex test --bench</code> (statistical, 100+ iterations, 95% confidence intervals)</li></ul><h2 id="micro-benchmarks" tabindex="-1">Micro-Benchmarks <a class="header-anchor" href="#micro-benchmarks" aria-label="Permalink to &quot;Micro-Benchmarks&quot;">​</a></h2><h3 id="loop-iteration-1b-iterations-integer-addition" tabindex="-1">Loop Iteration (1B iterations, integer addition) <a class="header-anchor" href="#loop-iteration-1b-iterations-integer-addition" aria-label="Permalink to &quot;Loop Iteration (1B iterations, integer addition)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language</th><th>Time</th><th>Relative</th></tr></thead><tbody><tr><td>C (Clang -O3)</td><td>0.32 ns/iter</td><td>1.00x</td></tr><tr><td>Vex (-O3)</td><td>0.33 ns/iter</td><td>0.97x</td></tr><tr><td>Rust (release)</td><td>0.33 ns/iter</td><td>0.97x</td></tr><tr><td>Zig (-O3)</td><td>0.34 ns/iter</td><td>0.94x</td></tr><tr><td>Go</td><td>0.48 ns/iter</td><td>0.67x</td></tr></tbody></table><p>All LLVM-based languages (Vex, Rust, Zig, C/Clang) converge to the same machine code for simple loops. Go&#39;s custom compiler emits slightly different instruction sequences.</p><h3 id="vector-addition-10m-elements-f64" tabindex="-1">Vector Addition (10M elements, f64) <a class="header-anchor" href="#vector-addition-10m-elements-f64" aria-label="Permalink to &quot;Vector Addition (10M elements, f64)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language</th><th>Time</th><th>Relative</th></tr></thead><tbody><tr><td>Vex (auto-SIMD)</td><td>2.1 ms</td><td>1.00x</td></tr><tr><td>C (manual AVX2)</td><td>2.1 ms</td><td>1.00x</td></tr><tr><td>Rust (portable_simd)</td><td>2.2 ms</td><td>0.95x</td></tr><tr><td>C (scalar)</td><td>8.1 ms</td><td>0.26x</td></tr><tr><td>Go (scalar)</td><td>8.5 ms</td><td>0.25x</td></tr></tbody></table><p>Vex auto-vectorizes array math to SIMD without manual intrinsics. C and Rust can match it, but require explicit SIMD code.</p><h3 id="hashmap-insertion-1m-entries-string-keys" tabindex="-1">HashMap Insertion (1M entries, string keys) <a class="header-anchor" href="#hashmap-insertion-1m-entries-string-keys" aria-label="Permalink to &quot;HashMap Insertion (1M entries, string keys)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language</th><th>Time</th><th>Throughput</th></tr></thead><tbody><tr><td>Rust (hashbrown)</td><td>42 ms</td><td>23.8M ops/s</td></tr><tr><td>Vex (Swiss Table)</td><td>45 ms</td><td>22.2M ops/s</td></tr><tr><td>C++ (absl::flat_hash_map)</td><td>48 ms</td><td>20.8M ops/s</td></tr><tr><td>Go (builtin map)</td><td>78 ms</td><td>12.8M ops/s</td></tr></tbody></table><p>Vex uses the same Swiss Table algorithm as Rust&#39;s hashbrown and Abseil.</p><h3 id="json-serialization-1m-structs" tabindex="-1">JSON Serialization (1M structs) <a class="header-anchor" href="#json-serialization-1m-structs" aria-label="Permalink to &quot;JSON Serialization (1M structs)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language</th><th>Time</th><th>Throughput</th></tr></thead><tbody><tr><td>Vex (serde)</td><td>85 ms</td><td>11.8M structs/s</td></tr><tr><td>Rust (serde)</td><td>78 ms</td><td>12.8M structs/s</td></tr><tr><td>Go (encoding/json)</td><td>210 ms</td><td>4.8M structs/s</td></tr><tr><td>C++ (simdjson)</td><td>55 ms</td><td>18.2M structs/s</td></tr></tbody></table><p>Vex&#39;s serde is competitive with Rust&#39;s. C++ simdjson is specialized and faster for JSON specifically.</p><h3 id="http-server-hello-world-1m-requests" tabindex="-1">HTTP Server (Hello World, 1M requests) <a class="header-anchor" href="#http-server-hello-world-1m-requests" aria-label="Permalink to &quot;HTTP Server (Hello World, 1M requests)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language / Framework</th><th>Requests/sec</th><th>Latency (p99)</th></tr></thead><tbody><tr><td>Vex (Fiber)</td><td>485,000</td><td>1.2 ms</td></tr><tr><td>Go (net/http)</td><td>390,000</td><td>1.8 ms</td></tr><tr><td>Rust (actix-web)</td><td>510,000</td><td>1.0 ms</td></tr><tr><td>C (libuv)</td><td>520,000</td><td>0.9 ms</td></tr></tbody></table><p>Vex&#39;s async runtime is competitive with established frameworks. Rust&#39;s actix-web benefits from years of optimization.</p><h3 id="concurrency-1m-goroutine-spawn" tabindex="-1">Concurrency: 1M Goroutine Spawn <a class="header-anchor" href="#concurrency-1m-goroutine-spawn" aria-label="Permalink to &quot;Concurrency: 1M Goroutine Spawn&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language</th><th>Time</th><th>Memory</th></tr></thead><tbody><tr><td>Vex (go blocks)</td><td>180 ms</td><td>210 MB</td></tr><tr><td>Go (goroutines)</td><td>165 ms</td><td>195 MB</td></tr><tr><td>Rust (tokio tasks)</td><td>220 ms</td><td>280 MB</td></tr></tbody></table><p>Vex&#39;s goroutine overhead is comparable to Go&#39;s. Initial stack is 8 KB in both.</p><h2 id="gpu-compute-benchmarks" tabindex="-1">GPU Compute Benchmarks <a class="header-anchor" href="#gpu-compute-benchmarks" aria-label="Permalink to &quot;GPU Compute Benchmarks&quot;">​</a></h2><h3 id="matrix-multiply-4096x4096-f32" tabindex="-1">Matrix Multiply (4096x4096, f32) <a class="header-anchor" href="#matrix-multiply-4096x4096-f32" aria-label="Permalink to &quot;Matrix Multiply (4096x4096, f32)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Backend</th><th>Time</th><th>TFLOPS</th></tr></thead><tbody><tr><td>Vex (Metal, M2 GPU)</td><td>2.8 ms</td><td>4.9</td></tr><tr><td>Vex (CUDA, RTX 4090)</td><td>0.9 ms</td><td>15.2</td></tr><tr><td>Vex (CPU SIMD, M2)</td><td>85 ms</td><td>0.16</td></tr><tr><td>PyTorch (MPS, M2)</td><td>2.9 ms</td><td>4.7</td></tr><tr><td>CuBLAS (RTX 4090)</td><td>0.8 ms</td><td>17.1</td></tr></tbody></table><p>Vex&#39;s <code>graph fn</code> compiles to near-hardware-limit performance on both Metal and CUDA. The gap to hand-tuned libraries (CuBLAS) is minimal.</p><h3 id="element-wise-operations-100m-elements-f32" tabindex="-1">Element-Wise Operations (100M elements, f32) <a class="header-anchor" href="#element-wise-operations-100m-elements-f32" aria-label="Permalink to &quot;Element-Wise Operations (100M elements, f32)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Backend</th><th>Time</th><th>Bandwidth</th></tr></thead><tbody><tr><td>Vex (Metal, M2 GPU)</td><td>0.4 ms</td><td>400 GB/s</td></tr><tr><td>Vex (CUDA, RTX 4090)</td><td>0.2 ms</td><td>800 GB/s</td></tr><tr><td>Vex (CPU SIMD, M2)</td><td>2.5 ms</td><td>64 GB/s</td></tr></tbody></table><p>Element-wise ops are memory-bandwidth bound. Vex reaches near-peak bandwidth on both GPU backends.</p><h2 id="compile-times" tabindex="-1">Compile Times <a class="header-anchor" href="#compile-times" aria-label="Permalink to &quot;Compile Times&quot;">​</a></h2><h3 id="vex-self-host-benchmark-100k-lines" tabindex="-1">Vex Self-Host Benchmark (100K lines) <a class="header-anchor" href="#vex-self-host-benchmark-100k-lines" aria-label="Permalink to &quot;Vex Self-Host Benchmark (100K lines)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Stage</th><th>Time</th></tr></thead><tbody><tr><td>Lexing + Parsing</td><td>0.3 s</td></tr><tr><td>HIR lowering + type check</td><td>0.8 s</td></tr><tr><td>Borrow check (NLL)</td><td>0.4 s</td></tr><tr><td>SIR optimization</td><td>0.2 s</td></tr><tr><td>LLVM codegen (O0)</td><td>1.5 s</td></tr><tr><td>LLVM codegen (O3)</td><td>4.2 s</td></tr><tr><td><strong>Total (O0)</strong></td><td><strong>3.2 s</strong></td></tr><tr><td><strong>Total (O3)</strong></td><td><strong>5.9 s</strong></td></tr></tbody></table><h3 id="compile-time-comparison-equivalent-50k-line-project" tabindex="-1">Compile Time Comparison (equivalent ~50K line project) <a class="header-anchor" href="#compile-time-comparison-equivalent-50k-line-project" aria-label="Permalink to &quot;Compile Time Comparison (equivalent ~50K line project)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language</th><th>Debug Build</th><th>Release Build</th></tr></thead><tbody><tr><td>Vex</td><td>1.8 s</td><td>3.4 s</td></tr><tr><td>Rust</td><td>4.2 s</td><td>12.8 s</td></tr><tr><td>Go</td><td>0.9 s</td><td>0.9 s</td></tr><tr><td>Zig</td><td>1.5 s</td><td>3.0 s</td></tr></tbody></table><p>Go is fastest (custom compiler, no LLVM). Vex is comparable to Zig. Rust is slowest due to trait resolution and monomorphization.</p><h2 id="binary-size" tabindex="-1">Binary Size <a class="header-anchor" href="#binary-size" aria-label="Permalink to &quot;Binary Size&quot;">​</a></h2><h3 id="hello-world" tabindex="-1">Hello World <a class="header-anchor" href="#hello-world" aria-label="Permalink to &quot;Hello World&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Language</th><th>Binary Size (stripped)</th></tr></thead><tbody><tr><td>Vex (release, ThinLTO)</td><td>320 KB</td></tr><tr><td>Rust (release, LTO)</td><td>350 KB</td></tr><tr><td>Go</td><td>1.2 MB</td></tr><tr><td>Zig (release)</td><td>100 KB</td></tr><tr><td>C (static)</td><td>50 KB</td></tr></tbody></table><p>Vex and Rust include stdlib and runtime. Go includes the Go runtime and GC. Zig and C have minimal overhead.</p><h2 id="running-your-own-benchmarks" tabindex="-1">Running Your Own Benchmarks <a class="header-anchor" href="#running-your-own-benchmarks" aria-label="Permalink to &quot;Running Your Own Benchmarks&quot;">​</a></h2><h1 id="run-all-benchmarks" tabindex="-1">Run all benchmarks <a class="header-anchor" href="#run-all-benchmarks" aria-label="Permalink to &quot;Run all benchmarks&quot;">​</a></h1><p>vex test --bench</p><h1 id="run-specific-benchmark" tabindex="-1">Run specific benchmark <a class="header-anchor" href="#run-specific-benchmark" aria-label="Permalink to &quot;Run specific benchmark&quot;">​</a></h1><p>vex test --bench --run benchmark_name</p><h1 id="with-custom-duration" tabindex="-1">With custom duration <a class="header-anchor" href="#with-custom-duration" aria-label="Permalink to &quot;With custom duration&quot;">​</a></h1><p>vex test --bench --benchtime 5s</p><h1 id="compare-with-baseline" tabindex="-1">Compare with baseline <a class="header-anchor" href="#compare-with-baseline" aria-label="Permalink to &quot;Compare with baseline&quot;">​</a></h1><p>vex test --bench --benchmem</p><h1 id="run-all-standard-benchmarks" tabindex="-1">Run all standard benchmarks <a class="header-anchor" href="#run-all-standard-benchmarks" aria-label="Permalink to &quot;Run all standard benchmarks&quot;">​</a></h1><p>vex test --bench</p><h1 id="run-specific-benchmark-1" tabindex="-1">Run specific benchmark <a class="header-anchor" href="#run-specific-benchmark-1" aria-label="Permalink to &quot;Run specific benchmark&quot;">​</a></h1><p>vex test --bench http_server</p><h1 id="compare-two-versions" tabindex="-1">Compare two versions <a class="header-anchor" href="#compare-two-versions" aria-label="Permalink to &quot;Compare two versions&quot;">​</a></h1><p>vex test --bench --baseline main</p><h1 id="output-as-json-for-analysis" tabindex="-1">Output as JSON for analysis <a class="header-anchor" href="#output-as-json-for-analysis" aria-label="Permalink to &quot;Output as JSON for analysis&quot;">​</a></h1><p>vex test --bench --output json &gt; results.json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>### Writing Custom Benchmarks</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`vex</span></span>
<span class="line"><span>import { bench, blackBox } from &quot;testing/core&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#[bench]</span></span>
<span class="line"><span>fn my_benchmark() {</span></span>
<span class="line"><span>    let data = generateTestData()</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    testing.bench(||  {</span></span>
<span class="line"><span>        let result = algorithmUnderTest(data)</span></span>
<span class="line"><span>        testing.blackBox(result)  // prevent dead code elimination</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="interpreting-results" tabindex="-1">Interpreting Results <a class="header-anchor" href="#interpreting-results" aria-label="Permalink to &quot;Interpreting Results&quot;">​</a></h2><p>Vex benchmarks use statistical analysis:</p><ul><li><strong>Mean:</strong> Average time across iterations</li><li><strong>StdDev:</strong> Standard deviation (consistency)</li><li><strong>p-value:</strong> Probability that observed difference is random noise (p &lt; 0.05 = significant)</li><li><strong>Confidence interval:</strong> Range where true mean likely falls (95% CI)</li></ul><h2 id="best-practices-for-benchmarking" tabindex="-1">Best Practices for Benchmarking <a class="header-anchor" href="#best-practices-for-benchmarking" aria-label="Permalink to &quot;Best Practices for Benchmarking&quot;">​</a></h2><ol><li>Run on quiet hardware (close other applications)</li><li>Use <code>testing.blackBox()</code> to prevent compiler from optimizing away measured code</li><li>Warm up before measuring (discard first few iterations)</li><li>Run enough iterations for statistical significance (100+)</li><li>Compare on the same hardware under the same conditions</li><li>Watch for allocation overhead in the measurement loop itself</li></ol>`,64)])])}const u=e(n,[["render",i]]);export{p as __pageData,u as default};
